import React, { createContext, useContext, useState } from 'react';
import { BrowserRouter, Routes, Route, NavLink, useLocation } from 'react-router-dom';
import './styles/global.css';
import Home from './pages/Home';
import Metro from './pages/Metro';
import Daily from './pages/Daily';
import Phrases from './pages/Phrases';
import Subscription from './Subscription';
export const AppContext = createContext();

export function useApp() {
  return useContext(AppContext);
}

function NavBar() {
  const location = useLocation();
  const navItems = [
    { to: '/', icon: '🏠', label: 'Accueil' },
    { to: '/metro', icon: '🚇', label: 'Métro' },
    { to: '/quotidien', icon: '🛒', label: 'Quotidien' },
    { to: '/phrases', icon: '💬', label: 'Phrases' },
  ];

  return (
    <nav style={{
      position: 'fixed', bottom: 0, left: 0, right: 0,
      background: 'var(--white)',
      borderTop: '1px solid var(--gray-100)',
      display: 'flex',
      zIndex: 100,
      paddingBottom: 'env(safe-area-inset-bottom)',
      boxShadow: '0 -4px 20px rgba(13,33,55,0.08)'
    }}>
      {navItems.map(item => (
        <NavLink
          key={item.to}
          to={item.to}
          end={item.to === '/'}
          style={({ isActive }) => ({
            flex: 1,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            padding: '10px 4px 8px',
            fontSize: 11,
            fontWeight: isActive ? 600 : 400,
            color: isActive ? 'var(--navy)' : 'var(--gray-400)',
            textDecoration: 'none',
            fontFamily: 'var(--font-body)',
            transition: 'color 0.2s',
            borderTop: isActive ? '2px solid var(--teal)' : '2px solid transparent',
          })}
        >
          <span style={{ fontSize: 20, marginBottom: 2 }}>{item.icon}</span>
          {item.label}
        </NavLink>
      ))}
    </nav>
  );
}

function Header() {
  const { lang, setLang } = useApp();
  const langOptions = [
    { code: 'en', flag: '🇬🇧' },
    { code: 'es', flag: '🇪🇸' },
    { code: 'ar', flag: '🇸🇦' },
    { code: 'zh', flag: '🇨🇳' },
  ];

  return (
    <header style={{
      background: 'var(--navy)',
      padding: '14px 20px 12px',
      position: 'sticky', top: 0, zIndex: 99,
      display: 'flex', alignItems: 'center', justifyContent: 'space-between'
    }}>
      <div>
        <div style={{
          fontFamily: 'var(--font-display)',
          fontSize: 22,
          fontWeight: 800,
          color: 'var(--white)',
          letterSpacing: '-0.5px'
        }}>
          Three<span style={{ color: 'var(--teal)' }}>Lingua</span>
        </div>
        <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.5)', marginTop: 1 }}>
          Paris & Île-de-France
        </div>
      </div>
      <div style={{ display: 'flex', gap: 6 }}>
        {langOptions.map(l => (
          <button
            key={l.code}
            onClick={() => setLang(l.code)}
            style={{
              width: 32, height: 32,
              borderRadius: '50%',
              border: lang === l.code ? '2px solid var(--teal)' : '2px solid rgba(255,255,255,0.15)',
              background: lang === l.code ? 'rgba(15,168,113,0.2)' : 'transparent',
              fontSize: 16,
              cursor: 'pointer',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              transition: 'all 0.2s'
            }}
          >
            {l.flag}
          </button>
        ))}
      </div>
    </header>
  );
}

export default function App() {
  const [lang, setLang] = useState('en');
  const [progress, setProgress] = useState({
    metroLinesViewed: [],
    dailyCatsViewed: [],
    phrasesPlayed: []
  });

  const updateProgress = (type, id) => {
    setProgress(prev => ({
      ...prev,
      [type]: prev[type].includes(id) ? prev[type] : [...prev[type], id]
    }));
  };

  return (
    <AppContext.Provider value={{ lang, setLang, progress, updateProgress }}>
      <BrowserRouter>
        <div style={{ maxWidth: 480, margin: '0 auto', minHeight: '100vh', position: 'relative', background: 'var(--off-white)' }}>
          <Header />
          <main style={{ paddingBottom: 80, minHeight: 'calc(100vh - 60px)' }}>
            <Routes>
              <Route path="/" element={<Home />} />
              <Route path="/metro" element={<Metro />} />
              <Route path="/quotidien" element={<Daily />} />
              <Route path="/phrases" element={<Phrases />} />
            </Routes><Route path="/subscription" element={<Subscription />} />
          </main>
          <NavBar />
        </div>
      </BrowserRouter>
    </AppContext.Provider>
  );
}
